concept.syntax:
// Create
let mut v: Vec<i32> = Vec::new();
let v = vec![1, 2, 3];    // macro shorthand

// Modify
v.push(4);                // append
v.pop();                  // remove last → Option<i32>

// Read
let first = v[0];         // panics if out of bounds
let first = v.get(0);     // returns Option<&i32>

// Iterate
for x in &v {
    println!("{}", x);
}

demo.code:
fn main() {
    let mut scores: Vec<i32> = Vec::new();
    scores.push(85);
    scores.push(92);
    scores.push(78);

    println!("count: {}", scores.len());
    println!("first: {}", scores[0]);

    let total: i32 = scores.iter().sum();
    println!("total: {}", total);

    for s in &scores {
        println!("{}", s);
    }
}

